"""Activity: Lookup Court

Seven questions putting attribute and method lookup on trial: given a snippet, where exactly is a read attribute found (instance __dict__, class __dict__, a base class, or nowhere at all); which method a diamond-inheritance call actually resolves to; what super() really consults (the __mro__, not simply 'the parent class'); whether assigning to an instance ever changes its class; what a bound method actually is; and why monkey-patching a class after instances already exist still changes what those existing instances do. Every explanation builds on dunder-dungeon's __dict__ and __mro__ groundwork.
"""
import json, sys

# -- Crypto / obfuscation --
_KEY_A = "799e3a483f2ef781994080bedf45acd057694fdaa7f5c4acbe23e013fd70c427"
_KEY_B = "9794bf79c478c3884f028ace018c9453a1dfe9f0fca80f7eb99383f0bc77fdb6"
import base64 as _b64, hashlib as _hl, hmac as _hm, json as _js, zlib as _zl

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000

# Split runtime key. This is obfuscation only; do not treat it as a secret.
def _xor_bytes(a, b):
    return bytes(x ^ y for x, y in zip(a, b))

def _runtime_key():
    return _xor_bytes(bytes.fromhex(_KEY_A), bytes.fromhex(_KEY_B))

def _derive_key(answers):
    return _hl.pbkdf2_hmac("sha256", "|".join(answers).encode(), _SALT, _KDF_ITERS)

def _stream(key, length):
    ks, i = b"", 0
    while len(ks) < length:
        ks += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return ks[:length]

def _decrypt(blob_hex, answers):
    blob    = bytes.fromhex(blob_hex)
    key     = _derive_key(answers)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    return bytes(a ^ b for a, b in zip(ct, _stream(key, len(ct)))).decode()

def _item_key(label):
    return _hm.new(_runtime_key(), label.encode(), _hl.sha256).digest()

def _open_secret(blob_text, label):
    try:
        blob = _b64.b85decode(blob_text.encode())
        key = _item_key(label)
        ct, mac = blob[:-32], blob[-32:]
        if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
            return None
        pt = _xor_bytes(ct, _stream(key, len(ct)))
        data = _js.loads(_zl.decompress(pt).decode())
        return data if isinstance(data, dict) else None
    except Exception:
        return None

